function implementQueueUsingStacks(data) {
    const text = (data || '').trim();
    if (!text) return 'None';

    const tokens = text.split(/\s+/);
    const q = [];
    const out = [];

    let i = 0;
    while (i < tokens.length) {
        const op = tokens[i++];
        if (op === 'push' && i < tokens.length) {
            q.push(parseInt(tokens[i++], 10));
            continue;
        }
        if (op === 'peek') {
            out.push(q.length ? String(q[0]) : 'None');
        } else if (op === 'pop') {
            out.push(q.length ? String(q.shift()) : 'None');
        }
    }

    return out.length ? out.join(' ') : 'None';
}

